/*
 * Memory Virtualization Simulation
 * Demonstrates how a hypervisor manages physical memory allocation
 * and creates virtual address spaces for each VM using shadow page tables.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define PAGE_SIZE 4096 // 4KB pages
#define MAX_VMS 10
#define MAX_PAGES 256

// Page table entry structure
typedef struct {
 unsigned int valid;
 unsigned int physical_page;
 unsigned int read_only;
} PageTableEntry;

// Virtual Machine structure
typedef struct {
 int vm_id;
 char name[32];
 unsigned int vmemory_size; // Virtual memory requested (MB)
 unsigned int assigned_physical; // Actual physical memory assigned
 unsigned int num_vpages; // Number of virtual pages
 PageTableEntry *shadow_page_table;
 unsigned int page_faults;
} VM;

// Hypervisor memory manager
typedef struct {
 unsigned int total_physical_memory; // Total RAM in MB
 unsigned int used_physical;
 unsigned int max_pages;
 unsigned char *physical_memory_map; // Track allocated physical pages
 VM *vms[MAX_VMS];
 int vm_count;
} HypervisorMemoryManager;

// Initialize memory manager
HypervisorMemoryManager* init_hypervisor(unsigned int total_ram_mb) {
 HypervisorMemoryManager *mgr = (HypervisorMemoryManager *)malloc(sizeof(HypervisorMemoryManager));
 mgr->total_physical_memory = total_ram_mb;
 mgr->used_physical = 0;
 mgr->max_pages = (total_ram_mb * 1024 * 1024) / PAGE_SIZE;
 mgr->physical_memory_map = (unsigned char *)calloc(mgr->max_pages, 1);
 mgr->vm_count = 0;

 printf("Hypervisor Memory Manager initialized:\n");
 printf(" Total Physical Memory: %u MB\n", total_ram_mb);
 printf(" Total Pages Available: %u\n", mgr->max_pages);
 printf(" Page Size: %d bytes\n\n", PAGE_SIZE);

 return mmgr;
}

// Allocate memory to a VM (demonstrates memory virtualization)
int allocate_vm_memory(HypervisorMemoryManager *mgr, VM *vm, int enable_overcommit) {
 // Calculate virtual pages needed
 vm->num_vpages = (vm->vmemory_size * 1024 * 1024) / PAGE_SIZE;

 printf("Allocating memory for VM '%s':\n", vm->name);
 printf(" Requested Virtual Memory: %u MB (%u pages)\n", 
 vm->vmemory_size, vm->num_vpages);

 // Check if we can allocate physical memory
 unsigned int available_mb = mgr->total_physical_memory - mgr->used_physical;

 if (!enable_overcommit && vm->vmemory_size > available_mb) {
 printf(" ERROR: Insufficient physical memory!\n");
 printf(" Available: %u MB, Requested: %u MB\n", 
 available_mb, vm->vmemory_size);
 return -1;
 }

 // Allocate physical pages for shadow page table
 vm->shadow_page_table = (PageTableEntry *)malloc(
 vm->num_vpages * sizeof(PageTableEntry));

 // Simulate memory allocation with shadow page tables
 // In real systems, this maps guest physical to host physical
 unsigned int pages_allocated = 0;

 for (unsigned int i = 0; i < vm->num_vpages; i++) {
 if (enable_overcommit || pages_allocated < mgr->max_pages) {
 // Find a free physical page
 unsigned int phys_page = 0;
 for (unsigned int p = 0; p < mgr->max_pages; p++) {
 if (mgr->physical_memory_map[p] == 0) {
 phys_page = p;
 mgr->physical_memory_map[p] = 1;
 break;
 }
 }

 // Create shadow page table entry (guest virtual -> host physical)
 vm->shadow_page_table[i].valid = 1;
 vm->shadow_page_table[i].physical_page = phys_page;
 vm->shadow_page_table[i].read_only = 0;

 pages_allocated++;
 } else {
 // Page not in memory (would cause page fault)
 vm->shadow_page_table[i].valid = 0;
 vm->page_faults++;
 }
 }

 vm->assigned_physical = (pages_allocated * PAGE_SIZE) / (1024 * 1024);
 mgr->used_physical += vm->assigned_physical;

 printf(" Allocated Physical Memory: %u MB (%u pages)\n", 
 vm->assigned_physical, pages_allocated);
 printf(" Shadow Page Tables Created: %u entries\n", vm->num_vpages);
 printf(" Memory Overcommit: %s\n\n", enable_overcommit ? "ENABLED" : "DISABLED");

 return 0;
}

// Simulate memory access through shadow page table
void simulate_memory_access(VM *vm, unsigned int vpage_num) {
 if (vpage_num >= vm->num_vpages) {
 printf(" Invalid virtual page access\n");
 return;
 }

 if (vm->shadow_page_table[vpage_num].valid) {
 printf(" ✓ Memory access: VM '%s' - Virtual Page %u -> Physical Page %u\n",
 vm->name, vpage_num, 
 vm->shadow_page_table[vpage_num].physical_page);
 } else {
 printf(" ✗ Page Fault: VM '%s' - Virtual Page %u not in physical memory\n",
 vm->name, vpage_num);
 vm->page_faults++;
 }
}

// Print memory statistics
void print_memory_stats(HypervisorMemoryManager *mgr) {
 printf("\n================== MEMORY STATISTICS ==================\n");
 printf("Total Physical Memory: %u MB\n", mgr->total_physical_memory);
 printf("Used Physical Memory: %u MB\n", mgr->used_physical);
 printf("Available Physical: %u MB\n", 
 mgr->total_physical_memory - mgr->used_physical);
 printf("Utilization: %.1f%%\n\n", 
 (float)mgr->used_physical / mgr->total_physical_memory * 100);

 printf("VM Memory Usage:\n");
 for (int i = 0; i < mgr->vm_count; i++) {
 VM *vm = mgr->vms[i];
 printf(" %s: %u MB virtual, %u MB physical, %u page faults\n",
 vm->name, vm->vmemory_size, vm->assigned_physical, vm->page_faults);
 }
}

int main() {
 printf("\n======================================================\n");
 printf(" HYPERVISOR MEMORY VIRTUALIZATION SIMULATION\n");
 printf(" Demonstrates Shadow Page Tables & Overcommit\n");
 printf("======================================================\n\n");

 // Initialize hypervisor with 16GB physical memory
 HypervisorMemoryManager *hypervisor = init_hypervisor(16384);

 // Create VMs with different memory requirements
 VM vms[4] = {
 {1, "WebServer", 4096, 0, 0, NULL, 0},
 {2, "Database", 8192, 0, 0, NULL, 0},
 {3, "AppServer", 2048, 0, 0, NULL, 0},
 {4, "TestVM", 4096, 0, 0, NULL, 0}
 };

 // Allocate memory to VMs WITHOUT overcommit
 printf("=== SCENARIO 1: Without Memory Overcommit ===\n");
 for (int i = 0; i < 3; i++) {
 allocate_vm_memory(hypervisor, &vms[i], 0);
 hypervisor->vms[hypervisor->vm_count++] = &vms[i];
 }

 // Try to allocate 4th VM without overcommit (should fail)
 printf("Trying to allocate 4th VM without overcommit...\n");
 allocate_vm_memory(hypervisor, &vms[3], 0);

 // Demonstrate memory access through shadow page tables
 printf("\n=== Simulating Memory Access ===\n");
 simulate_memory_access(&vms[0], 100); // Valid page
 simulate_memory_access(&vms[0], 1000); // Valid page
 simulate_memory_access(&vms[0], 50000); // Invalid (beyond allocated)

 print_memory_stats(hypervisor);

 printf("\n=== SCENARIO 2: With Memory Overcommit ===\n");
 // Reset for overcommit demonstration
 hypervisor->used_physical = 0;
 memset(hypervisor->physical_memory_map, 0, hypervisor->max_pages);

 // Allocate all VMs with overcommit enabled
 for (int i = 0; i < 4; i++) {
 vms[i].assigned_physical = 0;
 vms[i].page_faults = 0;
 if (vms[i].shadow_page_table) free(vms[i].shadow_page_table);
 allocate_vm_memory(hypervisor, &vms[i], 1);
 }

 print_memory_stats(hypervisor);

 printf("\n======================================================\n");
 printf(" Note: In production, overcommit requires\n");
 printf(" mechanisms like ballooning or swapping.\n");
 printf("======================================================\n\n");

 return 0;
}
